// ============================================================
// NORMALIZE CHANNEL INPUT
// Converts all incoming platform payloads into 3 unified vars:
// identifier, message, platform
// ============================================================

const input = $input.item.json;

let identifier = '';
let message = '';
let platform = '';
let firstName = '';
let email = '';

// --- TELEGRAM ---
if (input.message && input.message.message_id) {
  identifier = String(input.message.from.id);
  message = input.message.text || '';
  platform = 'telegram';
  firstName = input.message.from.first_name || '';
}

// --- FACEBOOK MESSENGER ---
else if (input.body && input.body.entry && input.body.entry[0] && input.body.entry[0].messaging) {
  const messaging = input.body.entry[0].messaging[0];
  identifier = messaging.sender.id;
  message = (messaging.message && messaging.message.text) ? messaging.message.text : '';
  platform = 'facebook';
}

// --- WHATSAPP (Twilio) ---
else if (input.body && input.body.From && input.body.From.includes('whatsapp:')) {
  identifier = input.body.From;
  message = input.body.Body || '';
  platform = 'whatsapp';
}

// --- SMS (Twilio) ---
else if (input.body && input.body.MessageSid) {
  identifier = input.body.From;
  message = input.body.Body || '';
  platform = 'sms';
}

// --- GMAIL ---
else if (input.from) {
  const fromRaw = input.from || '';
  const emailMatch = fromRaw.match(/<(.+?)>/) || [null, fromRaw];
  identifier = (emailMatch[1] || fromRaw).trim();
  message = input.text || input.snippet || '';
  platform = 'email';
  const nameMatch = fromRaw.match(/^([^<]+)/);
  firstName = nameMatch ? nameMatch[1].trim().split(' ')[0] : '';
  email = identifier;
}

// --- n8n CHAT ---
else if (input.sessionId) {
  identifier = input.sessionId;
  message = input.chatInput || '';
  platform = 'chat';
}

// --- GUARD: reject unidentifiable inputs ---
if (!identifier || !message) {
  throw new Error(
    'Normalize failed — could not detect platform. Input preview: ' +
    JSON.stringify(input).substring(0, 300)
  );
}

return {
  json: { identifier, message, platform, firstName, email }
};

// ============================================================
// UPDATE FIRST NAME TOOL
// !! IMPORTANT: Paste your Airtable Personal Access Token below
// Get it at: airtable.com → Account → Developer Hub → Personal Access Tokens
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const TABLE_ID = 'YOUR_LEADS_TABLE_ID';

const firstName = $fromAI('firstName', 'The first name provided by the lead in this message', 'string');
const recordId = $fromAI('recordId', 'The Airtable record ID of this lead — the "id" field from CURRENT LEAD INFO, starts with "rec"', 'string');

if (!recordId || !recordId.startsWith('rec')) {
  return 'Error: Invalid record ID. First name not saved.';
}

try {
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${TABLE_ID}/${recordId}`,
    {
      method: 'PATCH',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ fields: { 'First Name': firstName } })
    }
  );
  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }
  return `First name saved: "${firstName}" for record ${recordId}`;
} catch (e) {
  return `Failed to save first name: ${e.message}`;
}

// ============================================================
// UPDATE EMAIL TOOL
// !! IMPORTANT: Paste your Airtable Personal Access Token below
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const TABLE_ID = 'YOUR_LEADS_TABLE_ID';

const email = $fromAI('email', 'The email address provided by the lead', 'string');
const recordId = $fromAI('recordId', 'The Airtable record ID of this lead — the "id" field from CURRENT LEAD INFO, starts with "rec"', 'string');

if (!recordId || !recordId.startsWith('rec')) {
  return 'Error: Invalid record ID. Email not saved.';
}

// Basic email format validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  return `"${email}" does not look like a valid email address. Ask the lead to confirm it.`;
}

try {
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${TABLE_ID}/${recordId}`,
    {
      method: 'PATCH',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ fields: { 'Email': email } })
    }
  );
  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }
  return `Email saved: "${email}" for record ${recordId}`;
} catch (e) {
  return `Failed to save email: ${e.message}`;
}

// ============================================================
// UPDATE COMPANY TOOL
// !! IMPORTANT: Paste your Airtable Personal Access Token below
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const TABLE_ID = 'YOUR_LEADS_TABLE_ID';

const company = $fromAI('company', 'The company or business name provided by the lead', 'string');
const recordId = $fromAI('recordId', 'The Airtable record ID of this lead — the "id" field from CURRENT LEAD INFO, starts with "rec"', 'string');

if (!recordId || !recordId.startsWith('rec')) {
  return 'Error: Invalid record ID. Company not saved.';
}

try {
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${TABLE_ID}/${recordId}`,
    {
      method: 'PATCH',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ fields: { 'Company': company } })
    }
