  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }
  return `Company saved: "${company}" for record ${recordId}`;
} catch (e) {
  return `Failed to save company: ${e.message}`;
}

// ============================================================
// CLOSE DEAL TOOL
// Fires when customer agrees to move forward
// Triggers work ticket notification to Jake
// ============================================================

const leadRecordId = $fromAI('leadRecordId', 'The Airtable record ID of this lead — the "id" field from CURRENT LEAD INFO, starts with "rec"', 'string');
const sowRecordId = $fromAI('sowRecordId', 'The Airtable record ID of the Scope of Work record — returned from create_scope_of_work, starts with "rec"', 'string');
const customerName = $fromAI('customerName', 'The full name of the customer as collected in conversation', 'string');
const agentType = $fromAI('agentType', 'The type of agent they agreed to — e.g. Voice Receptionist, Lead Generation, etc.', 'string');
const buildPrice = $fromAI('buildPrice', 'The agreed build price as a number e.g. 997', 'number');
const monthlyPrice = $fromAI('monthlyPrice', 'The agreed monthly price as a number e.g. 499', 'number');

// Validate inputs
if (!leadRecordId || !leadRecordId.startsWith('rec')) {
  return 'Error: Invalid lead record ID. Cannot close deal.';
}

if (!sowRecordId || !sowRecordId.startsWith('rec')) {
  return 'Error: Invalid SOW record ID. Cannot close deal. Make sure create_scope_of_work was called first.';
}

try {
  const response = await fetch(
    'https://n8n.srv1436629.hstgr.cloud/webhook/wcai-deal-closed',
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        leadRecordId,
        sowRecordId,
        customerName: customerName || 'Unknown',
        agentType: agentType || 'Unknown',
        buildPrice: buildPrice || 0,
        monthlyPrice: monthlyPrice || 0
      })
    }
  );

  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }

  return `Deal closed successfully for ${customerName}. Jake has been notified with a full work ticket. The demo period has started — documents will be sent shortly.`;

} catch (e) {
  // Even if notification fails, tell Alex to continue gracefully
  return `Deal recorded. Jake will be in touch with ${customerName} shortly to get the paperwork over. If there are any delays, they can reach us at your-email@example.com`;
}

const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const SOW_TABLE_ID = 'YOUR_TABLE_4_ID';

const recordId = $fromAI('recordId', 'The Airtable record ID of this lead — the "id" field from CURRENT LEAD INFO, starts with "rec"', 'string');
const agentType = $fromAI('agentType', 'The type of agent they want — one of: Voice Receptionist, Lead Generation, Content Creation, Pro Build, Digital Employee', 'string');
const buildPrice = $fromAI('buildPrice', 'The agreed starting build price as a number e.g. 997', 'number');
const monthlyPrice = $fromAI('monthlyPrice', 'The agreed monthly price as a number e.g. 499', 'number');
const businessName = $fromAI('businessName', 'The name of their business if known, otherwise empty string', 'string');
const painPoint = $fromAI('painPoint', 'Their main pain point or reason for wanting the agent, in their own words', 'string');

if (!recordId || !recordId.startsWith('rec')) {
  return 'Error: Invalid lead record ID. Cannot create SOW.';
}

const demoStart = new Date();
const demoEnd = new Date();
demoEnd.setDate(demoEnd.getDate() + 14);

const fields = {
  'Lead': [{ 'id': recordId }],
  'Status': 'Draft',
  'Agent Type': agentType || '',
  'Demo Start Date': demoStart.toISOString().split('T')[0],
  'Demo End Date': demoEnd.toISOString().split('T')[0]
};

if (buildPrice) fields['Build Price'] = buildPrice;
if (monthlyPrice) fields['Monthly Price'] = monthlyPrice;
if (businessName) fields['Business Name'] = businessName;
if (painPoint) fields['Pain Point'] = painPoint;

try {
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${SOW_TABLE_ID}`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ fields })
    }
  );
  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }
  const data = await response.json();
  return `Scope of Work created successfully. SOW record ID: ${data.id}. Demo period: ${demoStart.toDateString()} to ${demoEnd.toDateString()}.`;
} catch (e) {
  return `Failed to create Scope of Work: ${e.message}`;
}

const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const SOW_TABLE_ID = 'YOUR_TABLE_4_ID';

const sowRecordId = $fromAI('sowRecordId', 'The Airtable record ID of the Scope of Work record — starts with "rec". Returned from create_scope_of_work.', 'string');
const fieldName = $fromAI('fieldName', 'The exact Airtable field name to update. Must be one of: Agent Type, Status, Build Price, Monthly Price, Demo Start Date, Demo End Date, Committed Date, Business Name, Industry, Location, Service Area, Hours of Operation, Website, Pain Point, Current Software, Additional Info, NDA Sent, NDA Signed, SOW Sent, SOW Signed, Payment Received, Build Complete, Agent Deployed, Notes', 'string');
const fieldValue = $fromAI('fieldValue', 'The value to set for the field. For checkboxes use true or false. For dates use YYYY-MM-DD format. For currency use a number.', 'string');

if (!sowRecordId || !sowRecordId.startsWith('rec')) {
  return 'Error: Invalid SOW record ID. Cannot update.';
}

if (!fieldName) {
  return 'Error: No field name provided.';
}

const validFields = [
  'Agent Type', 'Status', 'Build Price', 'Monthly Price',
  'Demo Start Date', 'Demo End Date', 'Committed Date',
  'Business Name', 'Industry', 'Location', 'Service Area',
  'Hours of Operation', 'Website', 'Pain Point',
  'Current Software', 'Additional Info',
  'NDA Sent', 'NDA Signed', 'SOW Sent', 'SOW Signed',
  'Payment Received', 'Build Complete', 'Agent Deployed', 'Notes'
];

if (!validFields.includes(fieldName)) {
  return `Error: "${fieldName}" is not a valid SOW field. Valid fields are: ${validFields.join(', ')}`;
}

let value = fieldValue;
const checkboxFields = ['NDA Sent', 'NDA Signed', 'SOW Sent', 'SOW Signed', 'Payment Received', 'Build Complete', 'Agent Deployed'];
const currencyFields = ['Build Price', 'Monthly Price'];

if (checkboxFields.includes(fieldName)) {
  value = fieldValue === 'true' || fieldValue === true;
}
if (currencyFields.includes(fieldName)) {
  value = parseFloat(fieldValue);
}

try {
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${SOW_TABLE_ID}/${sowRecordId}`,
    {
      method: 'PATCH',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ fields: { [fieldName]: value } })
    }
  );
  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }
  return `SOW updated: "${fieldName}" set to "${value}" for record ${sowRecordId}`;
} catch (e) {
  return `Failed to update SOW: ${e.message}`;
}

const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const SOW_TABLE_ID = 'YOUR_TABLE_4_ID';

const recordId = $fromAI('recordId', 'The Airtable record ID of this lead — the "id" field from CURRENT LEAD INFO, starts with "rec"', 'string');

if (!recordId || !recordId.startsWith('rec')) {
  return 'Error: Invalid lead record ID.';
}

try {
  const formula = encodeURIComponent(`FIND("${recordId}", ARRAYJOIN(Lead))`);
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${SOW_TABLE_ID}?filterByFormula=${formula}`,
    {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      }
    }
  );
  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }
  const data = await response.json();

  if (!data.records || data.records.length === 0) {
    return 'No existing Scope of Work found for this lead. If they agree to move forward, use create_scope_of_work.';
  }

  const sow = data.records[0];
  const fields = sow.fields;

  const filled = [];
  const missing = [];

  const allFields = [
    'Agent Type', 'Business Name', 'Industry', 'Location',
    'Service Area', 'Hours of Operation', 'Website',
    'Pain Point', 'Current Software', 'Additional Info'
  ];

  allFields.forEach(f => {
    if (fields[f]) {
      filled.push(`${f}: ${fields[f]}`);
    } else {
      missing.push(f);
    }
  });

  return JSON.stringify({
    sowRecordId: sow.id,
    status: fields['Status'] || 'Draft',
    agentType: fields['Agent Type'] || 'Not set',
    buildPrice: fields['Build Price'] || 'Not set',
    monthlyPrice: fields['Monthly Price'] || 'Not set',
    demoStart: fields['Demo Start Date'] || 'Not set',
    demoEnd: fields['Demo End Date'] || 'Not set',
    filledFields: filled,
    missingFields: missing,
    ndaSent: fields['NDA Sent'] || false,
    ndaSigned: fields['NDA Signed'] || false,
    sowSent: fields['SOW Sent'] || false,
    sowSigned: fields['SOW Signed'] || false,
    paymentReceived: fields['Payment Received'] || false,
    notes: fields['Notes'] || ''
  });
} catch (e) {
  return `Failed to retrieve Scope of Work: ${e.message}`;
}

// ============================================================
// LOG OUTCOME TOOL
// Captures what happened in every conversation
// Win or lose — always log it
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const SOW_TABLE_ID = 'YOUR_TABLE_4_ID';
const LEADS_TABLE_ID = 'YOUR_LEADS_TABLE_ID';

const sowRecordId = $fromAI('sowRecordId', 'The Airtable record ID of the Scope of Work — starts with rec. If no SOW exists yet pass empty string.', 'string');
const leadRecordId = $fromAI('leadRecordId', 'The Airtable record ID of the lead — the id field from CURRENT LEAD INFO, starts with rec', 'string');
const dealOutcome = $fromAI('dealOutcome', 'What happened — must be exactly one of: Won, Lost, Ghosted', 'string');
const lostReason = $fromAI('lostReason', 'If Lost, why — one of: Price, Not Interested, Bad Fit, No Response, Competitor. Leave empty if Won.', 'string');
const whatWorked = $fromAI('whatWorked', 'What resonated with the lead? What moved them forward or almost moved them? Be specific.', 'string');
const objectionsRaised = $fromAI('objectionsRaised', 'What objections did they raise? What concerns did they have? Be specific.', 'string');

const validOutcomes = ['Won', 'Lost', 'Ghosted'];
const validLostReasons = ['Price', 'Not Interested', 'Bad Fit', 'No Response', 'Competitor', ''];

if (!leadRecordId || !leadRecordId.startsWith('rec')) {
  return 'Error: Invalid lead record ID. Cannot log outcome.';
}

if (!validOutcomes.includes(dealOutcome)) {
  return `Error: Deal outcome must be Won, Lost, or Ghosted. Got: ${dealOutcome}`;
}

const results = [];

// Update SOW if we have a record ID
if (sowRecordId && sowRecordId.startsWith('rec')) {
  try {
    const sowFields = {
      'Deal Outcome': dealOutcome
    };
    if (lostReason && validLostReasons.includes(lostReason)) {
      sowFields['Lost Reason'] = lostReason;
    }
    if (whatWorked) sowFields['What Worked'] = whatWorked;
    if (objectionsRaised) sowFields['Objections Raised'] = objectionsRaised;

    const sowResponse = await fetch(
      `https://api.airtable.com/v0/${BASE_ID}/${SOW_TABLE_ID}/${sowRecordId}`,
      {
        method: 'PATCH',
        headers: {
          'Authorization': `Bearer ${AIRTABLE_PAT}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ fields: sowFields })
      }
    );
    if (sowResponse.ok) {
      results.push('SOW outcome logged');
    }
  } catch (e) {
    results.push(`SOW update failed: ${e.message}`);
  }
}

// Update lead status based on outcome
try {
  let newStatus = 'Contacted';
  if (dealOutcome === 'Won') newStatus = 'Closed';
  if (dealOutcome === 'Lost') newStatus = 'Contacted';
  if (dealOutcome === 'Ghosted') newStatus = 'Contacted';

  const leadResponse = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${LEADS_TABLE_ID}/${leadRecordId}`,
    {
      method: 'PATCH',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ 
        fields: { 'Status': newStatus }
      })
    }
  );
  if (leadResponse.ok) {
    results.push(`Lead status updated to ${newStatus}`);
  }
} catch (e) {
  results.push(`Lead update failed: ${e.message}`);
}

if (results.length === 0) {
  return 'Warning: Could not log outcome. Please try again.';
}

return `Outcome logged: ${dealOutcome}. ${results.join('. ')}.`;

// ============================================================
// CHECK CAPACITY TOOL
// Enforces daily build cap of 5
// Returns next available build date
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const QUEUE_TABLE_ID = 'YOUR_TABLE_2_ID';
const DAILY_CAP = 5;

// Get today and next 14 days to find availability
const today = new Date();
today.setHours(0, 0, 0, 0);

try {
  // Fetch all queued or in-progress builds
  const formula = encodeURIComponent(
    `OR({Build Status}='Queued', {Build Status}='In Progress')`
  );

  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${QUEUE_TABLE_ID}?filterByFormula=${formula}&fields[]=Scheduled+Build+Date&fields[]=Build+Status`,
    {
      headers: { 'Authorization': `Bearer ${AIRTABLE_PAT}` }
    }
  );

  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }

  const data = await response.json();
  const records = data.records || [];

  // Count builds per date
  const buildCounts = {};
  for (const record of records) {
    const date = record.fields['Scheduled Build Date'];
    if (date) {
      buildCounts[date] = (buildCounts[date] || 0) + 1;
    }
  }

  // Find next available date starting from today
  let availableDate = null;
  let daysChecked = 0;
  const checkDate = new Date(today);

  while (!availableDate && daysChecked < 30) {
    const dateStr = checkDate.toISOString().split('T')[0];
    const count = buildCounts[dateStr] || 0;

    // Skip weekends
    const dayOfWeek = checkDate.getDay();
    if (dayOfWeek !== 0 && dayOfWeek !== 6 && count < DAILY_CAP) {
      availableDate = dateStr;
    }

    checkDate.setDate(checkDate.getDate() + 1);
    daysChecked++;
  }

  if (!availableDate) {
    return JSON.stringify({
      available: false,
      message: 'Schedule is fully booked for the next 30 days. Please contact Jake directly at your-email@example.com',
      nextAvailableDate: null,
      todayCount: buildCounts[today.toISOString().split('T')[0]] || 0,
      dailyCap: DAILY_CAP
    });
  }

  const todayStr = today.toISOString().split('T')[0];
  const todayCount = buildCounts[todayStr] || 0;
  const isToday = availableDate === todayStr;

  // Format date nicely
  const dateObj = new Date(availableDate + 'T12:00:00');
  const formattedDate = dateObj.toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });

  return JSON.stringify({
    available: true,
    isToday: isToday,
    nextAvailableDate: availableDate,
    formattedDate: formattedDate,
    todayCount: todayCount,
    dailyCap: DAILY_CAP,
    slotsRemainingToday: Math.max(0, DAILY_CAP - todayCount),
    message: isToday
      ? `Great news — we have ${DAILY_CAP - todayCount} build slot${DAILY_CAP - todayCount !== 1 ? 's' : ''} available today. Build can start immediately after demo period.`
      : `Today's build slots are full. Next available build date is ${formattedDate}. Demo period starts today, build kicks off on that date.`
  });

} catch (e) {
  // Fail open — if capacity check fails don't block the sale
  return JSON.stringify({
    available: true,
    isToday: true,
    nextAvailableDate: new Date().toISOString().split('T')[0],
    formattedDate: 'as soon as possible',
    todayCount: 0,
    dailyCap: DAILY_CAP,
    slotsRemainingToday: DAILY_CAP,
    message: `Capacity check encountered an error but proceeding: ${e.message}`
  });
}

// ============================================================
// ADD TO BUILD QUEUE TOOL
// Adds customer to the build schedule
// Call after check_capacity returns an available date
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const QUEUE_TABLE_ID = 'YOUR_TABLE_2_ID';

const leadRecordId = $fromAI('leadRecordId', 'The Airtable record ID of the lead — starts with rec', 'string');
const sowRecordId = $fromAI('sowRecordId', 'The Airtable record ID of the Scope of Work — starts with rec', 'string');
const agentType = $fromAI('agentType', 'The type of agent being built e.g. Voice Receptionist Agent', 'string');
const scheduledDate = $fromAI('scheduledDate', 'The build date returned by check_capacity in YYYY-MM-DD format', 'string');

if (!leadRecordId || !leadRecordId.startsWith('rec')) {
  return 'Error: Invalid lead record ID.';
}

if (!sowRecordId || !sowRecordId.startsWith('rec')) {
  return 'Error: Invalid SOW record ID.';
}

if (!scheduledDate) {
  return 'Error: No scheduled date provided. Run check_capacity first.';
}

try {
  // Get current position count for that date
  const formula = encodeURIComponent(
    `{Scheduled Build Date}='${scheduledDate}'`
  );
  const countResponse = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${QUEUE_TABLE_ID}?filterByFormula=${formula}&fields[]=Position`,
    { headers: { 'Authorization': `Bearer ${AIRTABLE_PAT}` } }
  );
  const countData = await countResponse.json();
  const position = (countData.records || []).length + 1;

  // Add to queue
  const response = await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${QUEUE_TABLE_ID}`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        fields: {
          'Lead': [{ 'id': leadRecordId }],
          'SOW': [{ 'id': sowRecordId }],
          'Agent Type': agentType || '',
          'Scheduled Build Date': scheduledDate,
          'Build Status': 'Queued',
          'Position': position
        }
      })
    }
  );

  if (!response.ok) {
    const err = await response.text();
    throw new Error(err);
  }

  const data = await response.json();

  // Format date nicely for confirmation message
  const dateObj = new Date(scheduledDate + 'T12:00:00');
  const formattedDate = dateObj.toLocaleDateString('en-US', {
    weekday: 'long',
    month: 'long',
    day: 'numeric'
  });

  return `Successfully added to build queue. Position ${position} on ${formattedDate}. Queue record ID: ${data.id}`;

} catch (e) {
  return `Failed to add to build queue: ${e.message}`;
}

// ============================================================
// SEND CARD CAPTURE LINK TOOL
// Creates a Stripe Setup Intent and sends secure link to customer
// Call AFTER close_deal
// !! Replace PASTE_STRIPE_SECRET_KEY with your sk_test_ or sk_live_ key
// ============================================================
const STRIPE_SECRET_KEY = 'YOUR_STRIPE_SECRET_KEY';
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const LEADS_TABLE = 'YOUR_LEADS_TABLE_ID';
const SOW_TABLE = 'YOUR_TABLE_4_ID';

const leadRecordId = $fromAI('leadRecordId', 'The Airtable record ID of the lead — starts with rec', 'string');
const sowRecordId = $fromAI('sowRecordId', 'The Airtable record ID of the Scope of Work — starts with rec', 'string');
const customerName = $fromAI('customerName', 'The full name of the customer', 'string');
const customerEmail = $fromAI('customerEmail', 'The email address of the customer', 'string');
const buildAmount = $fromAI('buildAmount', 'The agreed build fee amount as a number e.g. 997', 'number');
const monthlyAmount = $fromAI('monthlyAmount', 'The agreed monthly fee amount as a number e.g. 499', 'number');
const agentType = $fromAI('agentType', 'The type of agent being built e.g. Voice Receptionist Agent', 'string');

if (!customerEmail) {
  return 'Error: Customer email is required to send card capture link. Make sure email has been collected.';
}

if (!leadRecordId || !leadRecordId.startsWith('rec')) {
  return 'Error: Invalid lead record ID.';
}

try {
  // Step 1 — Create Stripe Customer
  const customerBody = new URLSearchParams({
    'email': customerEmail,
    'name': customerName || '',
    'metadata[lead_record_id]': leadRecordId,
    'metadata[sow_record_id]': sowRecordId || '',
    'metadata[agent_type]': agentType || '',
    'metadata[build_amount]': String(buildAmount || 0),
    'metadata[monthly_amount]': String(monthlyAmount || 0),
    'metadata[customer_name]': customerName || '',
    'metadata[customer_email]': customerEmail
  });

  const customerResponse = await fetch('https://api.stripe.com/v1/customers', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: customerBody.toString()
  });

  if (!customerResponse.ok) {
    const err = await customerResponse.text();
    throw new Error(`Stripe customer creation failed: ${err}`);
  }

  const customer = await customerResponse.json();
  const customerId = customer.id;

  // Step 2 — Create Setup Intent
  const setupBody = new URLSearchParams({
    'customer': customerId,
    'payment_method_types[]': 'card',
    'usage': 'off_session',
    'metadata[lead_record_id]': leadRecordId,
    'metadata[sow_record_id]': sowRecordId || '',
    'metadata[customer_name]': customerName || '',
    'metadata[customer_email]': customerEmail,
    'metadata[build_amount]': String(buildAmount || 0),
    'metadata[monthly_amount]': String(monthlyAmount || 0)
  });

  const setupResponse = await fetch('https://api.stripe.com/v1/setup_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: setupBody.toString()
  });

  if (!setupResponse.ok) {
    const err = await setupResponse.text();
    throw new Error(`Stripe setup intent creation failed: ${err}`);
  }

  const setupIntent = await setupResponse.json();

  // Step 3 — Create Payment Link for card capture
  // Using Stripe hosted page for setup
  const sessionBody = new URLSearchParams({
    'mode': 'setup',
    'customer': customerId,
    'success_url': 'https://workingclassai.io/demo-confirmed?session_id={CHECKOUT_SESSION_ID}',
    'cancel_url': 'https://workingclassai.io/demo-cancelled',
    'payment_method_types[]': 'card',
    'metadata[lead_record_id]': leadRecordId,
    'metadata[sow_record_id]': sowRecordId || '',
    'metadata[customer_name]': customerName || '',
    'metadata[customer_email]': customerEmail,
    'metadata[build_amount]': String(buildAmount || 0),
    'metadata[monthly_amount]': String(monthlyAmount || 0)
  });

  const sessionResponse = await fetch('https://api.stripe.com/v1/checkout/sessions', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: sessionBody.toString()
  });

  if (!sessionResponse.ok) {
    const err = await sessionResponse.text();
    throw new Error(`Stripe checkout session creation failed: ${err}`);
  }

  const session = await sessionResponse.json();
  const cardCaptureUrl = session.url;

  // Step 4 — Send email to customer with card capture link
  const emailBody = new URLSearchParams({
    'from': 'your-email@example.com',
    'to': customerEmail,
    'subject': 'One last step — secure your Working Class AI demo',
    'html': `<p>Hey ${customerName ? customerName.split(' ')[0] : 'there'},</p>

<p>We are all set to kick off your free 14-day demo of your ${agentType || 'AI Agent'}. The last step is to securely add a card on file — nothing will be charged until after your demo period ends on day 14.</p>

<p><a href="${cardCaptureUrl}" style="background-color:#000;color:#fff;padding:12px 24px;text-decoration:none;border-radius:4px;display:inline-block;margin:16px 0;">Add Card on File — Secure Checkout</a></p>

<p>This is handled by Stripe — the same secure payment processor used by Amazon, Google, and millions of other businesses. Your card info is never stored on our servers.</p>

<p>Once your card is on file your demo starts immediately and Jake will begin building your agent. You will have it deployed and running within 7 business days.</p>

<p>Questions? Just reply to this email.</p>

<p>— Alex, Working Class AI</p>`
  });

  // Update Airtable with Stripe customer ID
  await fetch(
    `https://api.airtable.com/v0/${BASE_ID}/${LEADS_TABLE}/${leadRecordId}`,
    {
      method: 'PATCH',
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        fields: {
          'Stripe Customer ID': customerId
        }
      })
    }
  );

  return `Card capture link created and emailed to ${customerEmail}. Stripe Customer ID: ${customerId}. Setup Intent ID: ${setupIntent.id}. The customer will receive an email with a secure link to add their card. Demo starts automatically once they complete it.`;

} catch (e) {
  return `Failed to create card capture link: ${e.message}. Please send the customer to workingclassai.io to arrange payment manually or email your-email@example.com.`;
}

const params = $input.item.json.query;
const verifyToken = 'wcai_fb_verify_token';

if (params['hub.mode'] === 'subscribe' && params['hub.verify_token'] === verifyToken) {
  return { json: { response: params['hub.challenge'] } };
} else {
  throw new Error('Verification failed');
}
